[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP setup_prods]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 2 filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3 price.USD:(0 TO) inStock_variations:true") { items { id } } }
[GQL-EXEC setup_prods]
[GQL-CAPTURE setup_prods.data.products.items.0.id → PRODUCT_1]
[GQL-CAPTURE setup_prods.data.products.items.1.id → PRODUCT_2]
[GQL-OP pre_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC pre_clear]
[GQL-OP add_to_default]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "{{PRODUCT_1}}" quantity: 1 }) { id } }
[GQL-EXEC add_to_default]
[GQL-CAPTURE add_to_default.data.addItem.id → DEFAULT_CART_ID]
[GQL-OP add_to_second]
  mutation {
    addItem(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      cartName: "AGENT-TEST-MERGE-SECOND"
      productId: "{{PRODUCT_2}}" quantity: 1
    }) { id name itemsCount }
  }
[GQL-EXEC add_to_second]
[GQL-CAPTURE add_to_second.data.addItem.id → SECOND_CART_ID]
[GQL-OP merge]
  mutation {
    mergeCart(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      secondCartId: "{{SECOND_CART_ID}}"
    }) { id itemsCount items { productId } }
  }
[GQL-EXEC merge]
[GQL-OP cleanup_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_clear]

